import React, { useState, useContext, useEffect } from 'react';
import { AuthContext } from '../context/AuthContext';
import axios from 'axios';

const DoctorDashboard = () => {
  const { user } = useContext(AuthContext);

  const [todaysAppointments, setTodaysAppointments] = useState([]);
  const [appointmentHistory, setAppointmentHistory] = useState([]);
  const [patients, setPatients] = useState([]);
  const [availability, setAvailability] = useState([]);
  const [profile, setProfile] = useState({});
  const [editProfile, setEditProfile] = useState(false);
  const [newAvailabilityDate, setNewAvailabilityDate] = useState('');
  const [newAvailabilityTime, setNewAvailabilityTime] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Restrict access
  if (!user || user.role !== 'Doctor') {
    return <AccessDenied />;
  }

  // Fetch data once on mount
  useEffect(() => {
    const fetchData = async () => {
      if (!user) return;
      setLoading(true);
      try {
        const [
          apptsRes,
          historyRes,
          patientsRes,
          availabilityRes,
          profileRes
        ] = await Promise.all([
          axios.get('/api/doctor/today-appointments', { withCredentials: true }),
          axios.get('/api/doctor/appointment-history', { withCredentials: true }),
          axios.get('/api/doctor/patients', { withCredentials: true }),
          axios.get('/api/doctor/availability', { withCredentials: true }),
          axios.get('/api/auth/me', { withCredentials: true }),
        ]);

        setTodaysAppointments(apptsRes.data);
        setAppointmentHistory(historyRes.data);
        setPatients(patientsRes.data);
        setAvailability(availabilityRes.data);
        setProfile(profileRes.data); // ensure name/specialization/bio
      } catch (err) {
        console.error(err);
        setError('Failed to load dashboard data');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [user]);

  // Handlers
  const handleAddAvailability = async () => {
    if (!newAvailabilityDate || !newAvailabilityTime) {
      return alert('Please select date & time');
    }
    try {
      const res = await axios.post('/api/doctor/availability', {
        date: newAvailabilityDate,
        time: newAvailabilityTime
      }, { withCredentials: true });
      setAvailability(prev => [...prev, res.data]);
      setNewAvailabilityDate('');
      setNewAvailabilityTime('');
    } catch {
      alert('Failed to add availability');
    }
  };

  const handleProfileChange = e => {
    setProfile(prev => ({
      ...prev,
      [e.target.name]: e.target.value
    }));
  };

  const handleProfileSave = async () => {
    try {
      const res = await axios.put('/api/doctor/profile', profile, { withCredentials: true });
      setProfile(res.data);
      setEditProfile(false);
      alert('Profile updated!');
    } catch {
      alert('Failed to save profile');
    }
  };

  const handleStatusChange = async (id, newStatus) => {
    try {
      await axios.put(`/api/doctor/appointments/${id}/status`, { status: newStatus }, { withCredentials: true });
      setTodaysAppointments(prev =>
          prev.map(a => a._id === id ? { ...a, status: newStatus } : a)
      );
      alert('Status updated');
    } catch {
      alert('Failed to update status');
    }
  };

  if (loading) return <Loading />;
  if (error) return <Error message={error} />;

  return (
      <div className="min-h-screen bg-gray-100 p-6 text-gray-900 max-w-7xl mx-auto">
        <h1 className="text-3xl font-bold mb-6 text-center text-blue-700">Doctor Dashboard</h1>
        <div className="grid gap-6 md:grid-cols-2">
          {/* Today's Appointments */}
          <AppointmentsTable
              title="Today's Appointments"
              appointments={todaysAppointments}
              onStatusChange={handleStatusChange}
              isDoctor
          />

          {/* Manage Availability */}
          <AvailabilityManager
              availability={availability}
              date={newAvailabilityDate}
              time={newAvailabilityTime}
              setDate={setNewAvailabilityDate}
              setTime={setNewAvailabilityTime}
              onAdd={handleAddAvailability}
          />

          {/* Patient List */}
          <PatientsList patients={patients} />

          {/* Appointment History */}
          <AppointmentsTable title="Appointment History" appointments={appointmentHistory} />
        </div>

        {/* Profile Section */}
        <section className="mt-8 bg-white rounded-lg shadow p-5 max-w-3xl mx-auto">
          <h2 className="text-xl font-semibold mb-4">Profile Settings</h2>
          {editProfile ? (
              <form className="space-y-4" onSubmit={e => { e.preventDefault(); handleProfileSave(); }}>
                <FormInput label="Name" name="name" value={profile.name || ''} onChange={handleProfileChange} />
                <FormInput label="Specialization" name="specialization" value={profile.specialization || ''} onChange={handleProfileChange} />
                <textarea
                    name="bio"
                    value={profile.bio || ''}
                    onChange={handleProfileChange}
                    className="border rounded w-full p-2"
                    placeholder="Bio"
                />
                <div className="flex gap-3">
                  <button type="submit" className="bg-green-500 text-white px-4 py-2 rounded hover:bg-green-600">
                    Save
                  </button>
                  <button type="button" onClick={() => setEditProfile(false)} className="bg-gray-400 text-white px-4 py-2 rounded hover:bg-gray-500">
                    Cancel
                  </button>
                </div>
              </form>
          ) : (
              <div className="space-y-2">
                <p><strong>Name:</strong> {profile.name}</p>
                <p><strong>Specialization:</strong> {profile.specialization}</p>
                <p><strong>Bio:</strong> {profile.bio}</p>
                <button onClick={() => setEditProfile(true)} className="bg-blue-500 text-white px-3 py-1 mt-3 rounded hover:bg-blue-600">
                  Edit Profile
                </button>
              </div>
          )}
        </section>
      </div>
  );
};

export default DoctorDashboard;

// --- Helper Components ---
const AccessDenied = () => (
    <div className="flex items-center justify-center min-h-screen text-red-600 text-xl font-semibold">
      Access Denied: Doctors Only
    </div>
);
const Loading = () => (
    <div className="flex items-center justify-center min-h-screen"><p>Loading...</p></div>
);
const Error = ({ message }) => (
    <div className="flex items-center justify-center min-h-screen text-red-600">{message}</div>
);

const AppointmentsTable = ({ title, appointments, onStatusChange, isDoctor }) => (
    <section className="bg-white rounded-lg shadow p-5">
      <h2 className="text-xl font-semibold mb-4">{title}</h2>
      {appointments.length === 0 ? <p>No appointments found.</p> : (
          <table className="table-auto w-full text-sm border">
            <thead className="bg-blue-100">
            <tr>
              <th className="px-2 py-1">Patient</th>
              <th className="px-2 py-1">Time/Date</th>
              <th className="px-2 py-1">Status</th>
            </tr>
            </thead>
            <tbody>
            {appointments.map(a => (
                <tr key={a._id} className="border-t">
                  <td className="px-2 py-1">{a.user?.username}</td>
                  <td className="px-2 py-1">{new Date(a.appointmentDate).toLocaleString()}</td>
                  <td className="px-2 py-1">
                    {isDoctor ? (
                        <select
                            value={a.status}
                            onChange={e => onStatusChange(a._id, e.target.value)}
                            className="px-2 py-1 border rounded"
                        >
                          {['Pending','Confirmed','Cancelled','Completed'].map(s =>
                              <option key={s} value={s}>{s}</option>
                          )}
                        </select>
                    ) : (
                        <span className={`px-2 py-1 rounded ${
                            a.status === 'Confirmed' ? 'bg-green-100 text-green-800' :
                                a.status === 'Cancelled' ? 'bg-red-100 text-red-800' : 'bg-yellow-100 text-yellow-800'
                        }`}>{a.status}</span>
                    )}
                  </td>
                </tr>
            ))}
            </tbody>
          </table>
      )}
    </section>
);

const AvailabilityManager = ({ availability, date, time, setDate, setTime, onAdd }) => (
    <section className="bg-white rounded-lg shadow p-5">
      <h2 className="text-xl font-semibold mb-4">Manage Availability</h2>
      <div className="flex flex-col gap-2 mb-4">
        <input type="date" value={date} onChange={e => setDate(e.target.value)} className="border rounded px-2 py-1" />
        <input type="time" value={time} onChange={e => setTime(e.target.value)} className="border rounded px-2 py-1" />
        <button onClick={onAdd} className="bg-blue-500 text-white px-3 py-1 rounded hover:bg-blue-600">Add</button>
      </div>
      <ul className="list-disc ml-5">
        {availability.map(a => (
            <li key={a._id || a.id}>{a.date}: {a.timeSlots.join(', ')}</li>
        ))}
      </ul>
    </section>
);

const PatientsList = ({ patients }) => (
    <section className="bg-white rounded-lg shadow p-5">
      <h2 className="text-xl font-semibold mb-4">Patients</h2>
      {!patients.length ? <p>No patients found.</p> : (
          <ul className="space-y-2">
            {patients.map(p =>
                <li key={p._id || p.id} className="border p-2 rounded bg-gray-50">
                  {p.name}<br/><span className="text-sm text-gray-500">Last Visit: {new Date(p.lastVisit).toLocaleDateString()}</span>
                </li>
            )}
          </ul>
      )}
    </section>
);

const FormInput = ({ label, name, value, onChange }) => (
    <div>
      <label className="block mb-1 font-medium">{label}</label>
      <input
          type="text"
          name={name}
          value={value}
          onChange={onChange}
          className="border rounded w-full p-2"
      />
    </div>
);
